import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    min_weighted_delay = float('inf')
    best_node = None
    penalty_factor = 0.5  # Penalty factor for proximity to multiple trucks

    for i, customer in enumerate(unvisited_customers):
        distance = np.linalg.norm(cur_truck_pos - customer)
        potential_delay = 0
        proximity_penalty = 0

        for truck_pos in all_truck_pos:
            if np.array_equal(truck_pos, cur_truck_pos):
                continue
            alternative_distance = np.linalg.norm(truck_pos - customer)
            if alternative_distance < distance:
                potential_delay += distance - alternative_distance
            proximity_penalty += np.exp(-alternative_distance)  # Penalize close proximity exponentially

        weighted_delay = distance + potential_delay + penalty_factor * proximity_penalty

        if weighted_delay < min_weighted_delay:
            min_weighted_delay = weighted_delay
            best_node = i

    return best_node

import numpy as np

# {This algorithm iteratively chooses the next node for a truck by selecting the customer that maximizes the difference between the average distance of all trucks to all unvisited customers and the distance of the current truck to the selected customer, aiming to exploit potential beneficial waiting.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    avg_distances = np.array([
        np.mean([np.linalg.norm(truck_pos - customer) for truck_pos in all_truck_pos])
        for customer in unvisited_customers
    ])

    max_difference = -float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        cur_distance = np.linalg.norm(cur_truck_pos - customer)
        difference = avg_distances[i] - cur_distance

        if difference > max_difference:
            max_difference = difference
            best_node = i

    return best_node
